599	impl<T> Drop for SegQueue<T> {
600	    fn drop(&mut self) {
601	        let mut head = *self.head.index.get_mut();
602	        let mut tail = *self.tail.index.get_mut();
603	        let mut block = *self.head.block.get_mut();
604	
605	        // Erase the lower bits.
606	        head &= !((1 << SHIFT) - 1);
607	        tail &= !((1 << SHIFT) - 1);
608	
609	        unsafe {
610	            // Drop all values between `head` and `tail` and deallocate the heap-allocated blocks.
611	            while head != tail {
612	                let offset = (head >> SHIFT) % LAP;
613	
614	                if offset < BLOCK_CAP {
615	                    // Drop the value in the slot.
616	                    let slot = (*block).slots.get_unchecked(offset);
617	                    (*slot.value.get()).assume_init_drop();
618	                } else {
619	                    // Deallocate the block and move to the next one.
620	                    let next = *(*block).next.get_mut();
621	                    drop(Box::from_raw(block));
622	                    block = next;
623	                }
624	
625	                head = head.wrapping_add(1 << SHIFT);
626	            }
627	
628	            // Deallocate the last remaining block.
629	            if !block.is_null() {
630	                drop(Box::from_raw(block));
631	            }
632	        }
633	    }
634	}
